  const targetOption = selectedOptions[selectedOptions.length - 1]
  targetOption.loading = true
  // 选择第一级（镜像）后，调用接口获取第二级（目录）选项
  try {
    const res:any = await imagesFormat(repositoryId.value,selectedOptions[0].label)
    targetOption.loading = false
    if (res.code === '00000' && Array.isArray(res.respBody.data)) {
      targetOption.children = res.respBody.data.map((item) => ({
        label: item.imageName,
        value: item.imageName,
        isLeaf: true,
      }))
    } else {
      targetOption.children = []
    }
  } catch (error) {
    targetOption.loading = false
    targetOption.children = []
  }
  imageCascaderOptions.value = [...imageCascaderOptions.value]
}

const handleImageRepoChange = async (val) => {
  repositoryId.value = val
  // 根据当前镜像类型决定调用参数

  const query = imageType.value === 'preset' ? { project: 'preset-job-images' } : undefined
  const res:any = await imagesProjects(val, query)
  if (res.code === '00000' && Array.isArray(res.respBody.data)) {
    imageCascaderOptions.value = res.respBody.data.map((item) => ({
      label: item.name,
      value: item.name,
      isLeaf: false,
    }))
  }
}
// 切换类型时重置容器 tabs 激活项
watch(() => props.params.type, () => {
  activeKey.value = '1'
})
const handleImageTypeChange = async (val) => {
  imageType.value = val.imageType
  val.imageRepo = null as any
  val.imageCascader = null as any
  val.repositoryId = null as any
  if (repositoryId.value != '') {
    if (imageType.value === 'preset') {
      const res:any = await imagesProjects(repositoryId.value, { project: 'preset-job-images' })
      if (res.code === '00000' && Array.isArray(res.respBody.data)) {
        imageCascaderOptions.value = res.respBody.data.map((item) => ({
          label: item.name,
          value: item.name,
          isLeaf: false,
        }))
      }
    } else if (imageType.value === 'custom') {
      const res:any = await imagesProjects(repositoryId.value)
      if (res.code === '00000' && Array.isArray(res.respBody.data)) {
        imageCascaderOptions.value = res.respBody.data.map((item) => ({
          label: item.name,
          value: item.name,
          isLeaf: false,
        }))
      }
    }
  }
}

// 处理GPU型号切换
const handleGpuChange = (val) => {
  const gpu = gpuOptions.value.find(item => item.value === val);
  if (gpu) {
    gpuName.value = String(gpu.value);
    gpuType.value = String(gpu.type);
    props.containers.forEach((item) => {
      if (item.key == activeKey.value) {
        item.gpu = 1
      }
    })
  } else {
    props.containers.forEach((item) => {
      if (item.key == activeKey.value) {
        item.gpu = ''
      }
    })
  }
};

const getExamData = (val) => {
  if (val.name != '') {
    const id = val.tasks[0].containers[0].imageConfig.repositoryId
    const gpuName = val.tasks[0].containers[0].gpuName
    const image = val.tasks[0].containers[0].imageConfig.project
    const command = val.tasks[0].containers[0].command

    if (image == 'preset-job-images') {
      imageType.value = 'preset'
    } else {
      imageType.value = 'custom'
    }
    // 处理命令数据映射（不设默认，缺失则置空）
    if (Array.isArray(command) && command.length >= 1) {
      props.containers.forEach((container) => {
        container.commandShell = command[0] || ''
        container.commandText = command.length >= 3 ? (command[2] || '') : ''
      })
    }

    handleImageRepoChange(id);
    handleGpuChange(gpuName)
  }
};

onMounted(async () => {
  await fetchImageRepos()
  await fetchStoragePoolRoot()
  await fetchProtocol()
})
</script>

