const handleGpuChange = (val) => {
  const gpus = props.params.selectedQueueResource?.resources?.gpus;
  const gpu = Array.isArray(gpus) ? gpus.find(item => item.name === val) : null;
  if (gpu) {
    gpuName.value = String(gpu.name);
